const file = $input.item.json;
const name = file.name.toLowerCase();

let channel = "UNKNOWN";
if (name.includes("health")) channel = "HEALTH_HACKS";
else if (name.includes("money")) channel = "MONEYSTACK";

if (!['mp4','mov','avi'].some(ext => name.endsWith(ext))) throw new Error("Not video");

const ts = new Date().toISOString().split('T')[0].replace(/-/g,'');
const id = Math.random().toString(36).substring(2,6);

return {videoId: `${channel.toLowerCase()}-${ts}-${id}`, channel, filename: file.name, driveId: file.id};

const channel = $node['Extract Channel'].json.channel;
const transcript = $node['Whisper'].json.text;

const prompt = 'Channel: ' + channel + '\nTranscript: ' + transcript + '\n\nGenerate unique titles/descriptions for each platform. TikTok: viral hook. Instagram: aspirational story. YouTube: SEO educational. Output JSON: {"tiktok":{"title":"","caption":"","hashtags":[]},"instagram":{"title":"","caption":"","hashtags":[]},"youtube":{"title":"","description":"","tags":[]}}';

return {json: {prompt: prompt}};

const txt = $json.choices[0].message.content;
let c;
try {c = JSON.parse(txt);} catch {c = JSON.parse(txt.replace(/```json/g,'').replace(/```/g,'').trim());}
return {tiktok: c.tiktok, instagram: c.instagram, youtube: c.youtube};

const m = {video_id: $node['Extract Channel'].json.videoId, channel: $node['Extract Channel'].json.channel, filename: $node['Extract Channel'].json.filename, transcription: $node['Whisper'].json.text, content: {tiktok: $json.tiktok, instagram: $json.instagram, youtube: $json.youtube}, created: new Date().toISOString()};
const fs = require('fs'), d = '/workspace/.state/videos';
if (!fs.existsSync(d)) fs.mkdirSync(d, {recursive: true});
fs.writeFileSync(d + '/' + m.video_id + '.json', JSON.stringify(m, null, 2));
return {json: m};
